use std::io::{self, Read};

enum List {
    Cons(i64, Box<List>),
    Nil,
}

impl List {
    fn sum(&self) -> i64 {
        match self {
            List::Cons(value, next) => value + next.sum(),
            List::Nil => 0,
        }
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let values = input.split_whitespace().map(|part| part.parse::<i64>().unwrap()).collect::<Vec<_>>();
    let list = values.into_iter().rev().fold(List::Nil, |tail, value| List::Cons(value, Box::new(tail)));
    println!("{}", list.sum());
}

