rust-shared-state.reference_solution:
use std::io::{self, Read};
use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let values = input.split_whitespace().map(|part| part.parse::<i64>().unwrap()).collect::<Vec<_>>();
    let total = Arc::new(Mutex::new(0_i64));
    let mut handles = Vec::new();
    for value in values {
        let total = Arc::clone(&total);
        handles.push(thread::spawn(move || {
            let square = value * value;
            let mut guard = total.lock().expect("worker mutex poisoned");
            *guard += square;
        }));
    }
    for handle in handles {
        handle.join().expect("worker panicked");
    }
    let answer = *total.lock().expect("main mutex poisoned");
    println!("{answer}");
}
